import{_ as d,o as e,c as a,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"常见模型生态","description":"","frontmatter":{},"headers":[],"relativePath":"models/ecosystems.md","filePath":"models/ecosystems.md","lastUpdated":1782223980000}'),o={name:"models/ecosystems.md"};function r(i,t,s,n,h,m){return e(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="常见模型生态" tabindex="-1">常见模型生态 <a class="header-anchor" href="#常见模型生态" aria-label="Permalink to &quot;常见模型生态&quot;">​</a></h1><p>一句话：选择模型时，不只看画质，还要看生态、显存、LoRA、教程、工作流和许可证。</p><h2 id="对比表" tabindex="-1">对比表 <a class="header-anchor" href="#对比表" aria-label="Permalink to &quot;对比表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>生态</th><th>主要特点</th><th>适合场景</th><th>注意事项</th></tr></thead><tbody><tr><td>SD1.5</td><td>资源最多、显存低、老教程多</td><td>老插件、低显存、经典工作流</td><td>基础分辨率和画质较旧</td></tr><tr><td>SDXL</td><td>画质更好，1024 分辨率常见</td><td>通用绘画、插画、设计</td><td>LoRA 需 SDXL 兼容</td></tr><tr><td>Pony</td><td>二次元、角色、标签体系强</td><td>动漫角色、姿势、风格 LoRA</td><td>需要理解 score tag 和生态规则</td></tr><tr><td>Illustrious</td><td>二次元插画生态强</td><td>插画、角色、Danbooru 风格标签</td><td>不要默认与 Pony 混用</td></tr><tr><td>NoobAI</td><td>二次元标签体系</td><td>动漫插画、角色 LoRA</td><td>注意版本和 LoRA 兼容性</td></tr><tr><td>FLUX</td><td>语言理解和质感较强</td><td>真实感、设计、复杂提示词</td><td>工作流和 LoRA 生态不同于 SDXL</td></tr><tr><td>Qwen-Image</td><td>中文、多模态、文字渲染方向</td><td>中文提示词、图像理解、文字相关任务</td><td>模型较大，配置要求可能更高</td></tr><tr><td>Z-Image</td><td>新一代图像生成生态</td><td>速度、文字理解、中文或设计类任务</td><td>生态仍在发展，教程和 LoRA 较少</td></tr></tbody></table><h2 id="初学者怎么选" tabindex="-1">初学者怎么选 <a class="header-anchor" href="#初学者怎么选" aria-label="Permalink to &quot;初学者怎么选&quot;">​</a></h2><p>如果你主要学习概念和工具：</p><ul><li>低显存或老教程：SD1.5。</li><li>通用高质量图片：SDXL。</li><li>动漫、角色、LoRA：Pony / Illustrious / NoobAI。</li><li>新模型体验和自然语言提示词：FLUX / Qwen-Image / Z-Image。</li></ul><p>如果你只是想先学会 ComfyUI 或 WebUI，建议先固定一个生态，不要同时混用太多模型。</p><h2 id="看模型页面时重点看什么" tabindex="-1">看模型页面时重点看什么 <a class="header-anchor" href="#看模型页面时重点看什么" aria-label="Permalink to &quot;看模型页面时重点看什么&quot;">​</a></h2><p>下载模型前先看：</p><ul><li>Base model：它基于哪个生态。</li><li>Recommended settings：推荐尺寸、步数、CFG、采样器。</li><li>Trigger words：是否需要特定触发词。</li><li>License：能否商用，是否有限制。</li><li>Example prompts：作者示例怎么写。</li><li>Required files：是否需要额外 VAE、文本编码器或工作流。</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>只看排行榜。热门不代表适合你的用途。</li><li>忽略许可证。公开发布作品、商用、训练 LoRA 时尤其要看。</li><li>不看版本。模型、LoRA 和工作流经常按版本绑定。</li><li>把“模型生态”当成“单个文件”。新模型可能由多个文件组成，例如底模、文本编码器和 VAE。</li></ul>',13)])])}const p=d(o,[["render",r]]);export{u as __pageData,p as default};
